mapper.update:
UPDATE SWC_CODE C
SET
    C.CODE_NM = #{name, jdbcType=VARCHAR}
  , C.CODE_DC = #{description, jdbcType=VARCHAR}
  , C.CODE_SORT = #{sort, jdbcType=INTEGER}
  , C.CODE_TY = #{type, jdbcType=VARCHAR}
  , C.CODE_VALUE1 = #{value1, jdbcType=VARCHAR}
  , C.CODE_VALUE2 = #{value2, jdbcType=VARCHAR}
  , C.CODE_VALUE3 = #{value3, jdbcType=VARCHAR}
  , C.CODE_USE = UPPER (#{use, jdbcType=VARCHAR})
  , C.UPDT_DT = NOW()
  , C.UPDT_ID = #{updateId, jdbcType=VARCHAR}
WHERE
    C.CODE_ID = UPPER (#{id, jdbcType=VARCHAR})

mapper.delete:
DELETE FROM SWC_CODE WHERE CODE_ID IN (WITH RECURSIVE CODE_TREE AS (SELECT C.CODE_ID , C.CODE_UPPER_ID FROM SWC_CODE C WHERE C.CODE_ID = #{id, jdbcType=VARCHAR}
UNION ALL
SELECT C.CODE_ID , C.CODE_UPPER_ID FROM SWC_CODE C INNER JOIN CODE_TREE CT ON CT.CODE_ID = C.CODE_UPPER_ID) SELECT CODE_ID FROM CODE_TREE)
